python -c 'import logging,os,sys,runpy,traceback; logging.Formatter.formatException = lambda _, ei: "".join(traceback.TracebackException(*ei, capture_locals=True).format()); sys.excepthook = lambda t, v, tb: sys.stderr.write("".join(traceback.TracebackException(t, v, tb, capture_locals=True).format())); sys.argv=["uvicorn","main:app","--host","0.0.0.0"]; runpy.run_module("uvicorn", run_name="__main__")'